const i = items[0].json;
if (!i.profil) throw new Error('profil is required');
const body = {
  profil: String(i.profil).toLowerCase(),
  topic: i.topic || '',
  context: i.context || ''
};
if (i.provider) body.provider = String(i.provider).toLowerCase();
if (i.model) body.model = String(i.model);
if (i.project_id) body.project_id = String(i.project_id);
if (i.max_tokens !== undefined && i.max_tokens !== null && i.max_tokens !== '') body.max_tokens = Number(i.max_tokens);
if (i.temperature !== undefined && i.temperature !== null && i.temperature !== '') body.temperature = Number(i.temperature);
const bodyJson = JSON.stringify(body);
return [{ json: { bodyJson, profil: body.profil } }];

const r = items[0].json || {};
return [{ json: {
  status: r.status || 'error',
  project_id: r.project_id || null,
  profil: r.profil || $('Build Body').first().json.profil,
  provider: r.provider || null,
  script: r.script || null,
  raw: r.raw || null,
  error: r.error || null
} }];
